import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';  // ← ADD THIS IMPORT
import { motion } from 'framer-motion';
import { getProperties } from '../utils/api';

const Projects = () => {
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeFilter, setActiveFilter] = useState('All');

  useEffect(() => {
    fetchProperties();
  }, []);

  const fetchProperties = async () => {
    try {
      const response = await getProperties();
      setProperties(response.data);
    } catch (error) {
      console.error('Error fetching properties:', error);
    } finally {
      setLoading(false);
    }
  };

  const filters = ['All', 'Residential', 'Commercial'];

  const filteredProperties = properties.filter(property => {
    if (activeFilter === 'All') return true;
    return property.category === activeFilter;
  });

  const formatPrice = (price) => {
    if (price >= 10000000) return `₹${(price / 10000000).toFixed(2)} Cr`;
    if (price >= 100000) return `₹${(price / 100000).toFixed(1)} L`;
    return `₹${price.toLocaleString('en-IN')}`;
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      className="pt-32 pb-16 bg-gray-50 min-h-screen"
    >
      <div className="container-custom">
        <h1 className="text-4xl font-bold text-center mb-4 text-[#1a2332]">
          Our Properties
        </h1>
        <p className="text-center text-gray-600 mb-12">
          Discover premium residential and commercial properties in Nashik
        </p>

        {/* Filter Buttons */}
        <div className="flex flex-wrap justify-center gap-3 mb-12">
          {filters.map(filter => (
            <button
              key={filter}
              onClick={() => setActiveFilter(filter)}
              className={`px-5 py-2 rounded-lg font-medium transition ${
                activeFilter === filter 
                  ? 'bg-[#d4af37] text-[#1a2332] shadow-lg' 
                  : 'bg-white text-gray-700 hover:bg-gray-100 border'
              }`}
            >
              {filter}
            </button>
          ))}
        </div>

        {/* Properties Grid */}
        {loading ? (
          <div className="text-center py-12">Loading...</div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {filteredProperties.map((property) => (
              <div key={property._id} className="bg-white rounded-xl shadow-lg overflow-hidden hover:shadow-2xl transition hover:-translate-y-2">
                <div className="relative h-56">
                  <img 
                    src={property.images?.[0] || 'https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?w=800'} 
                    alt={property.title}
                    className="w-full h-full object-cover"
                  />
                  <div className="absolute top-4 right-4">
                    <span className={`px-3 py-1 rounded-full text-xs font-semibold text-white ${
                      property.listingType === 'Sale' ? 'bg-green-500' :
                      property.listingType === 'Rent' ? 'bg-blue-500' : 'bg-purple-500'
                    }`}>
                      {property.listingType}
                    </span>
                  </div>
                </div>
                <div className="p-5">
                  <h3 className="text-xl font-bold mb-2">{property.title}</h3>
                  <p className="text-gray-500 text-sm mb-2">{property.location?.area}, {property.location?.city}</p>
                  <p className="text-[#d4af37] font-bold text-2xl">{formatPrice(property.price)}</p>
                  <div className="flex gap-4 mt-3 text-sm text-gray-500">
                    {property.specifications?.bhk > 0 && <span>🛏️ {property.specifications.bhk} BHK</span>}
                    <span>📐 {property.specifications?.area} sq.ft</span>
                  </div>
                  {/* 👇👇👇 THIS IS THE BUTTON YOU NEED TO CHANGE 👇👇👇 */}
                  <Link to={`/property/${property._id}`}>
                    <button className="w-full mt-4 bg-[#d4af37] text-[#0a192f] py-2 rounded-lg font-semibold">
                      View Details
                    </button>
                  </Link>
                  {/* 👆👆👆 END OF BUTTON 👆👆👆 */}
                </div>
              </div>
            ))}
          </div>
        )}

        {!loading && filteredProperties.length === 0 && (
          <div className="text-center py-12">
            <p className="text-gray-500">No properties found.</p>
          </div>
        )}
      </div>
    </motion.div>
  );
};

export default Projects;
